import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface VideoMetadata {
  name: string;
  size: number;
  type: string;
  duration: string;
  thumbnail?: string;
}

export interface HookMoment {
  id: string;
  startTime: string;
  endTime: string;
  duration: number;
  title: string;
  description: string;
  viralityScore: number;
  captionPreview: string;
  suggestedEmojis: string[];
}

export interface ClipStats {
  totalClips: number;
  totalDuration: string;
  estimatedReach: string;
}

export interface AppState {
  step: 'upload' | 'analyzing' | 'gallery';
  videoFile: File | null;
  videoMetadata: VideoMetadata | null;
  hooks: HookMoment[];
  stats: ClipStats | null;
}

export enum AspectRatio {
  PORTRAIT = '9:16',
  LANDSCAPE = '16:9',
  SQUARE = '1:1'
}

export enum VideoStyle {
  CINEMATIC = 'Cinematic',
  FUNNY = 'Funny',
  DRAMATIC = 'Dramatic',
  AUTO = 'Auto'
}

import { GoogleGenAI, Type } from "@google/genai";
import { HookMoment, VideoMetadata } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeVideoWithAI = async (metadata: VideoMetadata): Promise<{ hooks: HookMoment[], topics: string[] }> => {
  const prompt = `
    Analyze this long-form video titled "${metadata.name}". 
    It is ${metadata.duration} long.
    Please identify 5-8 "viral hook" moments that would perform well on TikTok/Shorts/Reels.
    Return a list of hooks with:
    - id (unique)
    - startTime (MM:SS)
    - endTime (MM:SS)
    - title (punchy)
    - description (why it is viral)
    - viralityScore (0-100)
    - captionPreview (a short text of what's being said)
    - suggestedEmojis (array)
    - topics (array of 3-5 detected general topics)
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            hooks: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  startTime: { type: Type.STRING },
                  endTime: { type: Type.STRING },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  viralityScore: { type: Type.NUMBER },
                  captionPreview: { type: Type.STRING },
                  suggestedEmojis: {
                    type: Type.ARRAY,
                    items: { type: Type.STRING }
                  }
                },
                required: ["id", "startTime", "endTime", "title", "viralityScore"]
              }
            },
            topics: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["hooks", "topics"]
        }
      }
    });

    const result = JSON.parse(response.text || '{}');
    return {
      hooks: result.hooks || [],
      topics: result.topics || []
    };
  } catch (error) {
    console.error("AI Analysis failed:", error);
    // Fallback data if API fails
    return {
      hooks: [
        {
          id: '1',
          startTime: '00:15',
          endTime: '00:45',
          duration: 30,
          title: 'The Unfiltered Truth',
          description: 'High emotional stakes and direct eye contact.',
          viralityScore: 94,
          captionPreview: "You won't believe what happened next...",
          suggestedEmojis: ['🔥', '😱']
        }
      ],
      topics: ['Viral', 'Lifestyle', 'Storytelling']
    };
  }
};

import React, { useState, useCallback } from 'react';
import { Header } from './components/Header';
import { Uploader } from './components/Uploader';
import { AnalysisDashboard } from './components/AnalysisDashboard';
import { ClipGallery } from './components/ClipGallery';
import { CustomizationSidebar } from './components/CustomizationSidebar';
import { ExportBar } from './components/ExportBar';
import { AppState, VideoMetadata, HookMoment, ClipStats } from './types';
import { analyzeVideoWithAI } from './services/geminiService';

export default function App() {
  const [state, setState] = useState<AppState>({
    step: 'upload',
    videoFile: null,
    videoMetadata: null,
    hooks: [],
    stats: null
  });

  const [topics, setTopics] = useState<string[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const handleFileUpload = (file: File) => {
    // Simulate getting metadata
    const metadata: VideoMetadata = {
      name: file.name,
      size: file.size,
      type: file.type,
      duration: '42:15', // Mocked duration
      thumbnail: 'https://picsum.photos/seed/video/800/450'
    };

    setState(prev => ({
      ...prev,
      videoFile: file,
      videoMetadata: metadata,
      step: 'upload' // Stay on upload but show preview
    }));
  };

  const handleStartAnalysis = async () => {
    if (!state.videoMetadata) return;

    setState(prev => ({ ...prev, step: 'analyzing' }));

    // Real Gemini call
    const result = await analyzeVideoWithAI(state.videoMetadata);

    setTopics(result.topics);

    const stats: ClipStats = {
      totalClips: result.hooks.length,
      totalDuration: `${Math.floor(result.hooks.length * 45 / 60)}m ${result.hooks.length * 45 % 60}s`,
      estimatedReach: `${(result.hooks.length * 150).toLocaleString()}+ Views`
    };

    setState(prev => ({
      ...prev,
      step: 'gallery',
      hooks: result.hooks,
      stats: stats
    }));
  };

  const handleReset = () => {
    setState({
      step: 'upload',
      videoFile: null,
      videoMetadata: null,
      hooks: [],
      stats: null
    });
  };

  return (
    <div className="min-h-screen bg-[#0a0a0a] text-white flex flex-col">
      <Header onReset={handleReset} />

      <main className="flex-grow container mx-auto px-4 py-8 max-w-7xl">
        {state.step === 'upload' && (
          <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-8 animate-in fade-in duration-500">
            <Uploader 
              onUpload={handleFileUpload} 
              metadata={state.videoMetadata} 
              onAnalyze={handleStartAnalysis}
            />
          </div>
        )}

        {state.step === 'analyzing' && (
          <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-6">
            <div className="w-24 h-24 border-4 border-[#00ff88]/20 border-t-[#00ff88] rounded-full animate-spin"></div>
            <div className="text-center space-y-2">
              <h2 className="text-2xl font-bold">Analyzing with Coms AI...</h2>
              <p className="text-gray-400">Detecting hooks, emotions, and viral speech patterns (10-30s)</p>
            </div>
            <div className="w-full max-w-md bg-gray-900 rounded-full h-2 overflow-hidden">
               <div className="bg-[#00ff88] h-full animate-pulse" style={{ width: '65%' }}></div>
            </div>
          </div>
        )}

        {state.step === 'gallery' && (
          <div className="flex flex-col lg:flex-row gap-8">
            <div className="flex-grow space-y-8">
              <AnalysisDashboard stats={state.stats} topics={topics} />
              <ClipGallery clips={state.hooks} />
            </div>

            <aside className={`fixed inset-y-0 right-0 z-50 w-80 bg-[#111] border-l border-white/5 transform transition-transform duration-300 lg:relative lg:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : 'translate-x-full lg:translate-x-0'}`}>
              <CustomizationSidebar />
            </aside>

            {/* Mobile Sidebar Toggle (only visible on mobile) */}
            <button 
              onClick={() => setIsSidebarOpen(!isSidebarOpen)}
              className="lg:hidden fixed bottom-24 right-6 bg-[#00ff88] text-black p-4 rounded-full shadow-lg z-[60]"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" />
              </svg>
            </button>
          </div>
        )}
      </main>

      {state.step === 'gallery' && <ExportBar />}
    </div>
  );
}

