import React, { useRef, useState } from 'react';
import { VideoMetadata } from '../types';

interface UploaderProps {
  onUpload: (file: File) => void;
  onAnalyze: () => void;
  metadata: VideoMetadata | null;
}

export const Uploader: React.FC<UploaderProps> = ({ onUpload, onAnalyze, metadata }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isDragging, setIsDragging] = useState(false);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) onUpload(file);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = () => setIsDragging(false);

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files?.[0];
    if (file) onUpload(file);
  };

  if (metadata) {
    return (
      <div className="w-full max-w-3xl space-y-6 animate-in zoom-in-95 duration-300">
        <div className="bg-[#111] rounded-2xl overflow-hidden border border-white/5 glow-green">
          <img src={metadata.thumbnail} className="w-full h-64 object-cover opacity-60" alt="Preview" />
          <div className="p-8">
            <div className="flex justify-between items-start mb-6">
              <div>
                <h3 className="text-2xl font-bold mb-1">{metadata.name}</h3>
                <p className="text-gray-400 text-sm">{(metadata.size / (1024 * 1024)).toFixed(2)} MB • {metadata.duration}</p>
              </div>
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="text-gray-400 hover:text-white transition-colors text-sm"
              >
                Change video
              </button>
            </div>

            <button 
              onClick={onAnalyze}
              className="w-full bg-[#00ff88] text-black py-4 rounded-xl font-bold text-lg hover:bg-[#00cc6e] transition-all transform active:scale-[0.98]"
            >
              Analyze with AI ✨
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="w-full max-w-3xl">
      <div 
        onClick={() => fileInputRef.current?.click()}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
        className={`
          relative cursor-pointer border-2 border-dashed rounded-[32px] p-16 transition-all duration-300
          flex flex-col items-center text-center space-y-6
          ${isDragging ? 'bg-[#00ff88]/5 border-[#00ff88] scale-[1.02]' : 'bg-[#111]/50 border-white/10 hover:border-[#00ff88]/50 hover:bg-[#111]'}
        `}
      >
        <input 
          type="file" 
          ref={fileInputRef} 
          onChange={handleFileChange} 
          className="hidden" 
          accept="video/*"
        />

        <div className="w-20 h-20 bg-[#00ff88]/10 rounded-full flex items-center justify-center text-[#00ff88] group-hover:scale-110 transition-transform">
          <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
          </svg>
        </div>

        <div className="space-y-2">
          <h2 className="text-3xl font-bold">Upload Long Video</h2>
          <p className="text-gray-400">Drag and drop MP4, MOV or MKV (up to 60min)</p>
        </div>

        <div className="pt-4 flex gap-4 text-xs font-medium uppercase tracking-widest text-gray-500">
          <span className="bg-white/5 px-3 py-1.5 rounded-md">Auto Hooks</span>
          <span className="bg-white/5 px-3 py-1.5 rounded-md">Dynamic Captions</span>
          <span className="bg-white/5 px-3 py-1.5 rounded-md">Smart Framing</span>
        </div>
      </div>

      <div className="mt-8 bg-amber-500/10 border border-amber-500/20 p-4 rounded-xl flex items-center gap-4 text-amber-200 text-sm">
        <svg className="w-5 h-5 flex-shrink-0" fill="currentColor" viewBox="0 0 20 20">
          <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
        </svg>
        <p>Free Tier: You have <span className="font-bold">25 minutes</span> remaining this week. Upgrade for unlimited processing.</p>
      </div>
    </div>
  );
};

