            <img src={metadata.thumbnail} className="w-full h-full object-cover opacity-50 transition-transform duration-1000 group-hover:scale-105" alt="Preview" />
            <div className="absolute inset-0 bg-gradient-to-t from-[#111] to-transparent"></div>
