              <span className="bg-[#00ff88] text-black text-[10px] font-black uppercase px-2 py-0.5 rounded mr-2">Ready</span>
              <h3 className="text-2xl font-black mt-1">{metadata.name}</h3>
            </div>
          </div>
          <div className="p-10 pt-4">
            <div className="flex justify-between items-center mb-10 text-gray-500 text-xs font-medium tracking-widest uppercase">
              <p>{(metadata.size / (1024 * 1024)).toFixed(1)} MB • {metadata.duration}</p>
              <button onClick={() => fileInputRef.current?.click()} className="hover:text-white transition-colors underline decoration-[#00ff88]/40 underline-offset-4">Change File</button>
            </div>

            <button 
              onClick={onAnalyze}
              className="group relative w-full bg-[#00ff88] text-black py-5 rounded-2xl font-black text-xl hover:bg-[#00cc6e] transition-all transform hover:-translate-y-1 shadow-[0_10px_30px_rgba(0,255,136,0.3)]"
            >
              <span className="relative z-10 flex items-center justify-center gap-3">
                Analyze with Coms AI
                <svg className="w-6 h-6 animate-pulse" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>
              </span>
              <div className="absolute inset-0 rounded-2xl bg-white opacity-0 group-hover:opacity-10 transition-opacity"></div>
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="w-full max-w-3xl">
      <div 
        onClick={() => fileInputRef.current?.click()}
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={(e) => { e.preventDefault(); setIsDragging(false); const f = e.dataTransfer.files[0]; if(f) onUpload(f); }}
        className={`
          relative cursor-pointer border-2 border-dashed rounded-[3rem] p-20 transition-all duration-500
          flex flex-col items-center text-center space-y-8
          ${isDragging ? 'bg-[#00ff88]/5 border-[#00ff88] scale-[1.03] shadow-[0_0_50px_rgba(0,255,136,0.1)]' : 'bg-[#111]/30 border-white/5 hover:border-[#00ff88]/40 hover:bg-[#111]/60 shadow-inner'}
        `}
      >
        <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept="video/*" />

        <div className="relative">
          <div className="w-24 h-24 bg-[#00ff88]/10 rounded-[2rem] flex items-center justify-center text-[#00ff88] transform -rotate-6 transition-transform hover:rotate-0">
            <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
            </svg>
          </div>
          <div className="absolute -bottom-2 -right-2 w-8 h-8 bg-[#00ff88] text-black rounded-lg flex items-center justify-center shadow-lg transform rotate-12">
             <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 3a1 1 0 011 1v5h5a1 1 0 110 2h-5v5a1 1 0 11-2 0v-5H4a1 1 0 110-2h5V4a1 1 0 011-1z" clipRule="evenodd"/></svg>
          </div>
        </div>

        <div className="space-y-3">
          <h2 className="text-4xl font-black tracking-tight leading-tight">Drop your video here.</h2>
          <p className="text-gray-500 text-lg">We'll turn your long content into viral shorts in seconds.</p>
        </div>

        <div className="flex items-center gap-6 text-[10px] font-black uppercase tracking-[0.2em] text-gray-500">
          <div className="flex items-center gap-2 bg-white/5 px-4 py-2 rounded-full"><div className="w-1.5 h-1.5 rounded-full bg-[#00ff88]"></div> 9:16 Auto-Crop</div>
