        <div className="absolute inset-0 bg-gradient-to-r from-[#00ff88]/5 to-transparent pointer-events-none"></div>
        <div className="flex items-center gap-5 relative z-10">
          <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-xl ${minutesRemaining < 10 ? 'bg-red-500/10 text-red-500' : 'bg-[#00ff88]/10 text-[#00ff88]'}`}>
