import React, { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { Uploader } from './components/Uploader';
import { AnalysisDashboard } from './components/AnalysisDashboard';
import { ClipGallery } from './components/ClipGallery';
import { CustomizationSidebar } from './components/CustomizationSidebar';
import { ExportBar } from './components/ExportBar';
import { Tutorial } from './components/Tutorial';
import { AppState, VideoMetadata, HookMoment, ClipStats } from './types';
import { analyzeVideoWithAI } from './services/geminiService';

export default function App() {
  const [state, setState] = useState<AppState>({
    step: 'upload',
    videoFile: null,
    videoMetadata: null,
    hooks: [],
    stats: null
  });

  const [topics, setTopics] = useState<string[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [showTutorial, setShowTutorial] = useState(false);

  const handleFileUpload = (file: File) => {
    const metadata: VideoMetadata = {
      name: file.name,
      size: file.size,
      type: file.type,
      duration: '42:15',
      thumbnail: 'https://images.unsplash.com/photo-1498050108023-c5249f4df085?auto=format&fit=crop&q=80&w=800&h=450',
      sourceType: 'file'
    };

    setState(prev => ({
      ...prev,
      videoFile: file,
      videoMetadata: metadata,
      step: 'upload'
    }));
  };

  const handleYouTubeImport = (url: string) => {
    // Extract ID for a realistic thumbnail simulation
    const regExp = /^.*(youtu\.be\/|v\/|u\/\w\/|embed\/|watch\?v=|\&v=)([^#\&\?]*).*/;
    const match = url.match(regExp);
    const videoId = (match && match[2].length === 11) ? match[2] : 'dQw4w9WgXcQ';

    const metadata: VideoMetadata = {
      name: "Imported YouTube Video", // In a real app, this would be fetched from API
      size: 0,
      type: 'video/youtube',
      duration: '18:45',
      thumbnail: `https://img.youtube.com/vi/${videoId}/maxresdefault.jpg`,
      sourceType: 'youtube',
      youtubeUrl: url
    };

    setState(prev => ({
      ...prev,
      videoMetadata: metadata,
      step: 'upload'
    }));
  };

  const handleStartAnalysis = async () => {
    if (!state.videoMetadata) return;

    setState(prev => ({ ...prev, step: 'analyzing' }));

    const result = await analyzeVideoWithAI(state.videoMetadata);

    setTopics(result.topics);

    const stats: ClipStats = {
      totalClips: result.hooks.length,
      totalDuration: `${Math.floor(result.hooks.length * 45 / 60)}m ${result.hooks.length * 45 % 60}s`,
      estimatedReach: `${(result.hooks.length * 150).toLocaleString()}+ Views`
    };

    setState(prev => ({
      ...prev,
      step: 'gallery',
      hooks: result.hooks,
      stats: stats
    }));

    if (!localStorage.getItem('tutorial_seen')) {
      setShowTutorial(true);
    }
  };

  const handleReset = () => {
    setState({
      step: 'upload',
      videoFile: null,
      videoMetadata: null,
      hooks: [],
      stats: null
    });
  };

  const closeTutorial = () => {
    setShowTutorial(false);
    localStorage.setItem('tutorial_seen', 'true');
  };

  return (
    <div className="min-h-screen bg-[#0a0a0a] text-white flex flex-col selection:bg-[#00ff88] selection:text-black">
      <Header onReset={handleReset} />

      <main className="flex-grow container mx-auto px-4 py-8 max-w-7xl">
        {state.step === 'upload' && (
          <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <Uploader 
              onUpload={handleFileUpload} 
              onYouTubeImport={handleYouTubeImport}
              metadata={state.videoMetadata} 
              onAnalyze={handleStartAnalysis}
            />
          </div>
        )}

        {state.step === 'analyzing' && (
          <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-6">
            <div className="relative">
              <div className="w-24 h-24 border-4 border-[#00ff88]/10 border-t-[#00ff88] rounded-full animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                <div className="w-12 h-12 bg-[#00ff88]/20 rounded-full animate-pulse"></div>
              </div>
            </div>
            <div className="text-center space-y-2 max-w-sm">
              <h2 className="text-2xl font-bold bg-gradient-to-r from-white to-gray-500 bg-clip-text text-transparent">
                Designing Viral Hooks...
              </h2>
              <p className="text-gray-400 text-sm">Identifying high-retention speech patterns and emotional triggers.</p>
            </div>
            <div className="w-full max-w-md bg-white/5 rounded-full h-1.5 overflow-hidden">
               <div className="bg-[#00ff88] h-full transition-all duration-1000 ease-out shadow-[0_0_10px_#00ff88]" style={{ width: '75%' }}></div>
            </div>
          </div>
        )}

        {state.step === 'gallery' && (
          <div className="flex flex-col lg:flex-row gap-8 animate-in fade-in duration-500">
            <div className="flex-grow space-y-8">
              <AnalysisDashboard stats={state.stats} topics={topics} />
              <ClipGallery clips={state.hooks} />
            </div>

            <aside className={`fixed inset-y-0 right-0 z-50 w-85 bg-[#0d0d0d] border-l border-white/5 transform transition-transform duration-500 lg:relative lg:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : 'translate-x-full lg:translate-x-0'}`}>
              <CustomizationSidebar onRegenerate={handleStartAnalysis} />
            </aside>

            <button 
              onClick={() => setIsSidebarOpen(!isSidebarOpen)}
              className="lg:hidden fixed bottom-24 right-6 bg-[#00ff88] text-black p-4 rounded-full shadow-2xl z-[60] hover:scale-110 active:scale-95 transition-all"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.3} d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" />
              </svg>
            </button>
          </div>
        )}
      </main>

      {state.step === 'gallery' && <ExportBar />}
      {showTutorial && <Tutorial onClose={closeTutorial} />}
    </div>
  );
}

