  const handleYtSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!ytUrl.trim()) return;

    // Basic URL validation
    const ytRegex = /^(https?:\/\/)?(www\.)?(youtube\.com|youtu\.be)\/.+$/;
    if (!ytRegex.test(ytUrl)) {
      setError('Please enter a valid YouTube URL');
      return;
    }

    setError(null);
    setIsImporting(true);

