          <div className="w-20 h-20 bg-white/5 rounded-[2rem] flex items-center justify-center text-white/40 transition-all group-hover:bg-[#00ff88]/10 group-hover:text-[#00ff88] group-hover:scale-110 group-hover:rotate-3">
