                  border-2 rounded transition-colors
                  ${ratio === AspectRatio.PORTRAIT ? 'w-4 h-6' : ratio === AspectRatio.LANDSCAPE ? 'w-6 h-4' : 'w-5 h-5'}
                  ${aspect === ratio ? 'border-[#00ff88]' : 'border-current'}
                `}></div>
                <span className="text-[9px] font-black uppercase">{ratio}</span>
              </button>
            ))}
          </div>
        </section>

        {/* Manual Hooks */}
        <section className="space-y-5">
          <label className="text-[10px] font-black uppercase tracking-[0.2em] text-gray-600 block">Hook Strategy (Prompt)</label>
          <textarea 
            placeholder="Focus on the most controversial parts..." 
            className="w-full bg-white/5 border border-white/5 rounded-2xl p-5 text-xs text-gray-300 focus:border-[#00ff88] focus:ring-0 outline-none transition-all h-32 resize-none placeholder:text-gray-700 font-medium leading-relaxed"
          />
        </section>

        <div className="pt-6">
          <button 
            onClick={onRegenerate}
            className="w-full bg-white text-black py-5 rounded-[1.5rem] font-black text-sm hover:scale-105 active:scale-95 transition-all shadow-2xl flex items-center justify-center gap-3"
          >
            Regenerate Clips
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"/></svg>
          </button>
        </div>
      </div>
    </div>
  );
};

export interface CaptionWord {
  text: string;
  start: number; // seconds
  end: number; // seconds
}

export interface CaptionSegment {
  text: string;
  words: CaptionWord[];
}

export interface VideoMetadata {
  name: string;
  size: number;
  type: string;
  duration: string;
  thumbnail?: string;
  sourceType: 'file' | 'youtube';
  youtubeUrl?: string;
}

export interface HookMoment {
  id: string;
  startTime: string;
  endTime: string;
  duration: number;
  title: string;
  description: string;
  viralityScore: number;
  captionPreview: string;
  suggestedEmojis: string[];
  segments?: CaptionSegment[];
  hashtags?: string[];
}

export interface ClipStats {
  totalClips: number;
  totalDuration: string;
  estimatedReach: string;
}

export interface AppState {
  step: 'upload' | 'analyzing' | 'gallery';
  videoFile: File | null;
  videoMetadata: VideoMetadata | null;
  hooks: HookMoment[];
  stats: ClipStats | null;
  captionColor: string;
}

export enum AspectRatio {
  PORTRAIT = '9:16',
  LANDSCAPE = '16:9',
  SQUARE = '1:1'
}

export enum VideoStyle {
  CINEMATIC = 'Cinematic',
  FUNNY = 'Funny',
  DRAMATIC = 'Dramatic',
  AUTO = 'Auto'
}

import { GoogleGenAI, Type } from "@google/genai";
import { HookMoment, VideoMetadata } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeVideoWithAI = async (metadata: VideoMetadata): Promise<{ hooks: HookMoment[], topics: string[] }> => {
  const prompt = `
    Analyze this long-form video titled "${metadata.name}". 
    It is ${metadata.duration} long.
    Please identify 5-8 "viral hook" moments that would perform well on TikTok/Shorts/Reels.

    For each hook, also generate:
    1. A word-level transcription for the "caption preview" part (approx 5-10 words).
    2. A list of 5-8 trending and highly relevant hashtags (without the # symbol).

    Return a list of hooks with:
    - id (unique)
    - startTime (MM:SS)
    - endTime (MM:SS)
    - title (punchy)
    - description (why it is viral)
    - viralityScore (0-100)
    - captionPreview (a short text of what's being said)
    - suggestedEmojis (array)
    - segments (an array containing one segment with its words, each word having 'text', 'start', and 'end' times relative to hook start)
    - hashtags (array of strings, e.g. ["viral", "podcast", "mindset"])
    - topics (array of 3-5 detected general topics)
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            hooks: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  startTime: { type: Type.STRING },
                  endTime: { type: Type.STRING },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  viralityScore: { type: Type.NUMBER },
                  captionPreview: { type: Type.STRING },
                  suggestedEmojis: {
                    type: Type.ARRAY,
                    items: { type: Type.STRING }
                  },
                  hashtags: {
                    type: Type.ARRAY,
                    items: { type: Type.STRING }
                  },
                  segments: {
                    type: Type.ARRAY,
                    items: {
                      type: Type.OBJECT,
                      properties: {
                        text: { type: Type.STRING },
                        words: {
                          type: Type.ARRAY,
                          items: {
                            type: Type.OBJECT,
                            properties: {
                              text: { type: Type.STRING },
                              start: { type: Type.NUMBER },
                              end: { type: Type.NUMBER }
                            }
                          }
                        }
                      }
                    }
                  }
                },
                required: ["id", "startTime", "endTime", "title", "viralityScore"]
              }
            },
            topics: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["hooks", "topics"]
        }
      }
    });

    const result = JSON.parse(response.text || '{}');
    return {
      hooks: result.hooks || [],
      topics: result.topics || []
    };
  } catch (error) {
    console.error("AI Analysis failed:", error);
    // Fallback data if API fails
    return {
      hooks: [
        {
          id: '1',
          startTime: '00:15',
          endTime: '00:45',
          duration: 30,
          title: 'The Unfiltered Truth',
          description: 'High emotional stakes and direct eye contact.',
          viralityScore: 94,
          captionPreview: "Believe in your dreams always",
          suggestedEmojis: ['🔥', '😱'],
          hashtags: ["motivation", "success", "viral", "dreams", "unfiltered"],
          segments: [{
            text: "Believe in your dreams always",
            words: [
              { text: "Believe", start: 0, end: 0.5 },
              { text: "in", start: 0.5, end: 0.7 },
              { text: "your", start: 0.7, end: 1.0 },
              { text: "dreams", start: 1.0, end: 1.5 },
              { text: "always", start: 1.5, end: 2.0 }
            ]
          }]
        }
      ],
      topics: ['Viral', 'Lifestyle', 'Storytelling']
    };
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { HookMoment } from '../types';

interface ClipCardProps {
  clip: HookMoment;
  index: number;
  captionColor: string;
}

export const ClipCard: React.FC<ClipCardProps> = ({ clip, index, captionColor }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [showShareMenu, setShowShareMenu] = useState(false);
  const [showHashtags, setShowHashtags] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [copied, setCopied] = useState(false);

  // Simulated playback time for caption synchronization
  useEffect(() => {
    let interval: any;
    if (isPlaying) {
      interval = setInterval(() => {
        setCurrentTime(prev => (prev + 0.1) % 5); // Loop every 5s for demo
      }, 100);
    } else {
      setCurrentTime(0);
    }
    return () => clearInterval(interval);
  }, [isPlaying]);

  const activeWords = useMemo(() => {
    if (!clip.segments?.[0]?.words) return [];
    return clip.segments[0].words;
  }, [clip]);

  const handleCopyHashtags = () => {
    const hashtagStr = clip.hashtags?.map(h => `#${h}`).join(' ') || '';
    navigator.clipboard.writeText(hashtagStr);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="group bg-[#111] rounded-[2rem] overflow-hidden border border-white/5 hover:border-[#00ff88]/30 transition-all duration-500 flex flex-col h-full hover:shadow-[0_20px_60px_-15px_rgba(0,255,136,0.1)]">
      <div className="relative aspect-[9/16] bg-black overflow-hidden cursor-pointer" onClick={() => setIsPlaying(!isPlaying)}>
        <img 
          src={`https://images.unsplash.com/photo-1622737133809-d95047b9e673?auto=format&fit=crop&q=60&w=450&h=800&seed=${clip.id}`} 
          className={`w-full h-full object-cover transition-transform duration-700 ${isPlaying ? 'scale-110' : 'group-hover:scale-105'}`}
          alt="Clip Thumbnail"
        />

        {/* Visual Noise Layer */}
        <div className="absolute inset-0 bg-black/10 mix-blend-overlay pointer-events-none"></div>

        {/* Dynamic Animated Caption Simulation */}
        <div className={`absolute inset-x-0 bottom-16 px-6 text-center transition-all duration-300 ${isPlaying ? 'opacity-100 translate-y-0' : 'opacity-80 translate-y-2'}`}>
          <div className="flex flex-wrap justify-center gap-x-2 bg-black/40 py-2 backdrop-blur-md rounded-2xl inline-flex px-4 border border-white/5">
            {activeWords.length > 0 ? (
              activeWords.map((word, i) => {
                const isActive = currentTime >= word.start && currentTime <= word.end;
                return (
                  <span 
                    key={i} 
                    className="text-2xl font-black uppercase italic tracking-tighter transition-all duration-150"
                    style={{ 
                      color: isActive ? captionColor : 'white',
                      transform: isActive ? 'scale(1.2) translateY(-2px)' : 'scale(1)',
                      textShadow: isActive ? `0 0 10px ${captionColor}44` : '0 2px 10px rgba(0,0,0,1)'
                    }}
                  >
                    {word.text}
                  </span>
                );
              })
            ) : (
              <p className="text-[#00ff88] text-2xl font-black uppercase italic tracking-tighter drop-shadow-[0_2px_10px_rgba(0,0,0,1)]">
                {clip.captionPreview} {clip.suggestedEmojis.join('')}
              </p>
            )}
          </div>
        </div>

        {!isPlaying && (
          <div className="absolute inset-0 flex items-center justify-center bg-black/40 group-hover:bg-black/10 transition-all">
            <div className="w-20 h-20 bg-[#00ff88] rounded-full flex items-center justify-center text-black shadow-[0_0_30px_rgba(0,255,136,0.5)] transform transition-transform group-hover:scale-110">
              <svg className="w-10 h-10 ml-1.5" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z"/></svg>
            </div>
          </div>
        )}

        <div className="absolute top-6 left-6 flex flex-col gap-2">
          <div className="bg-black/60 backdrop-blur-md text-[#00ff88] text-[9px] font-black py-1.5 px-3 rounded-full border border-[#00ff88]/20 tracking-widest uppercase">
            Viral Hook #{index}
          </div>
          {clip.viralityScore > 90 && (
             <div className="bg-amber-500 text-black text-[9px] font-black py-1 px-2.5 rounded-full w-fit animate-bounce">
               TRENDING 🚀
             </div>
          )}
        </div>

        <div className="absolute top-6 right-6 flex flex-col items-end gap-2">
           <div className="bg-[#00ff88] text-black text-sm font-black py-2 px-4 rounded-2xl shadow-xl flex items-center gap-1.5">
             <span className="text-[10px] opacity-70">SCORE</span> {clip.viralityScore}%
           </div>
        </div>
      </div>

      <div className="p-8 space-y-6 flex-grow flex flex-col relative">
        <div className="flex-grow">
          <h4 className="font-black text-xl leading-[1.2] mb-3 group-hover:text-[#00ff88] transition-colors line-clamp-2">
            {clip.title}
          </h4>
          <div className="flex items-center gap-2 mb-4">
             <span className="bg-white/5 text-gray-400 text-[10px] font-bold px-2 py-1 rounded border border-white/5">{clip.startTime} - {clip.endTime}</span>
             <span className="text-gray-600 font-bold">•</span>
             <span className="text-xs text-gray-500 font-medium">Auto-detected Speaker: Host</span>
          </div>
          <p className="text-xs text-gray-500 leading-relaxed italic border-l-2 border-[#00ff88]/30 pl-3">"{clip.description}"</p>
        </div>

        <div className="space-y-3 pt-4 border-t border-white/5 relative">
          <div className="grid grid-cols-2 gap-2">
            <button className="flex items-center justify-center gap-2 py-3.5 rounded-2xl bg-white/5 border border-white/5 hover:bg-white/10 text-xs font-black transition-all group/btn">
              <svg className="w-4 h-4 text-[#00ff88]" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"/></svg>
              Edit Clip
            </button>
            <button 
              onClick={() => setShowHashtags(!showHashtags)}
              className={`flex items-center justify-center gap-2 py-3.5 rounded-2xl border transition-all text-xs font-black ${showHashtags ? 'bg-[#00ff88]/10 border-[#00ff88]/30 text-[#00ff88]' : 'bg-white/5 border-white/5 text-gray-400 hover:bg-white/10 hover:text-white'}`}
            >
              <span className="text-lg">#</span>
              AI Hashtags
            </button>
          </div>

          <div className="flex gap-2">
            <button className="flex-grow flex items-center justify-center gap-2 py-4 rounded-2xl bg-[#00ff88] text-black font-black text-sm hover:bg-[#00cc6e] transition-all shadow-lg active:scale-95">
               <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0L8 8m4-4v12"/></svg>
              Download MP4
            </button>
            <button 
              onClick={() => setShowShareMenu(!showShareMenu)}
              className="px-5 flex items-center justify-center rounded-2xl bg-white/5 border border-white/5 hover:bg-white/10 transition-all"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z"/></svg>
            </button>
          </div>

          {/* AI Hashtags Popover */}
          {showHashtags && (
            <div className="absolute bottom-full left-0 right-0 mb-4 bg-[#1a1a1a] border border-[#00ff88]/20 rounded-2xl p-6 shadow-2xl animate-in fade-in slide-in-from-bottom-2 z-30">
              <div className="flex items-center justify-between mb-4">
                <span className="text-[10px] font-black uppercase tracking-widest text-[#00ff88]">AI Optimized Hashtags</span>
                <button onClick={() => setShowHashtags(false)} className="text-gray-500 hover:text-white transition-colors">
                   <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12"/></svg>
                </button>
              </div>
              <div className="flex flex-wrap gap-2 mb-6">
                {clip.hashtags?.map((tag, i) => (
                  <span key={i} className="bg-[#00ff88]/5 border border-[#00ff88]/10 text-[#00ff88] text-[10px] font-bold px-2 py-1 rounded-lg">
                    #{tag}
                  </span>
                ))}
              </div>
              <button 
                onClick={handleCopyHashtags}
                className={`w-full py-3 rounded-xl font-black text-xs uppercase tracking-widest transition-all flex items-center justify-center gap-2 ${copied ? 'bg-green-500 text-white' : 'bg-white text-black hover:bg-gray-200'}`}
              >
                {copied ? 'Copied to Clipboard! ✓' : 'Copy All Hashtags'}
              </button>
            </div>
          )}

          {showShareMenu && (
            <div className="absolute bottom-full left-0 right-0 mb-4 bg-[#1a1a1a] border border-white/10 rounded-2xl p-4 shadow-2xl animate-in fade-in slide-in-from-bottom-2 grid grid-cols-4 gap-2 z-20">
               {[
                 { n: 'TikTok', i: '🎵' },
                 { n: 'Insta', i: '📸' },
                 { n: 'Youtube', i: '▶️' },
                 { n: 'Copy', i: '🔗' }
               ].map(social => (
                 <button key={social.n} className="flex flex-col items-center gap-1 hover:bg-white/5 p-2 rounded-xl transition-colors">
                    <span className="text-xl">{social.i}</span>
                    <span className="text-[8px] font-black uppercase text-gray-500">{social.n}</span>
                 </button>
               ))}
               <button onClick={() => setShowShareMenu(false)} className="absolute -top-2 -right-2 bg-white text-black w-6 h-6 rounded-full flex items-center justify-center font-bold text-xs shadow-xl">×</button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};
